function toNumber(v) {
  if (v === null || v === undefined || v === '') return 0;
  const n = Number(String(v).replace(/[$,%\s,]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

function colToA1(colIndex1Based) {
  let n = colIndex1Based;
  let out = '';
  while (n > 0) {
    const m = (n - 1) % 26;
    out = String.fromCharCode(65 + m) + out;
    n = Math.floor((n - 1) / 26);
  }
  return out;
}

function normalizeHeader(value) {
  return String(value || '').replace(/[^A-Za-z0-9]/g, '').toUpperCase();
}

const sheet = $('Webhook Read Google Sheet').first().json || {};
const values = sheet.values || [];
const sheetName = $('Set Credentials').first().json['✅SHEET_NAME'];

// ✨ FIX: Read parsed sku data from the actual upstream Report parser nodes
const fbaBySku = $('SP Parse Returns by SKU').first().json.bySku || {};
const fbmBySku = $('SP Parse FBM Stock by SKU').first().json.bySku || {};

// ✨ FIX: Safely combine FBA and FBM stock amounts for each SKU
const stockBySku = {};
for (const sku of new Set([...Object.keys(fbaBySku), ...Object.keys(fbmBySku)])) {
  const fbaQty = fbaBySku[sku] ? (fbaBySku[sku].fbaTotalQuantity || 0) : 0;
  const fbmQty = fbmBySku[sku] ? (fbmBySku[sku].fbmQuantity || 0) : 0;
  stockBySku[sku] = fbaQty + fbmQty;
}

const headerRow = values[0] || [];
const skuCol = headerRow.findIndex((cell) => normalizeHeader(cell) === 'SKU');
const targetCol = headerRow.findIndex((cell) => normalizeHeader(cell) === 'FBAFBMSTOCK');

if (skuCol === -1 || targetCol === -1) {
  throw new Error('Could not find SKU and FBA_FBM_STOCK columns');
}

const targetColA1 = colToA1(targetCol + 1);
const data = [];
for (let i = 1; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  if (!sku || /^SKU$/i.test(sku) || /^IMG$/i.test(sku) || /_TOTALS$/i.test(sku)) continue;

  data.push({
    range: `${sheetName}!${targetColA1}${i + 1}`,
    values: [[toNumber(stockBySku[sku] || 0)]],
  });
}

return [{ json: { valueInputOption: 'USER_ENTERED', data } }];

function parseDelimitedLine(line, delimiter) {
  const out = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }
    if (ch === delimiter && !inQuotes) {
      out.push(current);
      current = '';
      continue;
    }
    current += ch;
  }
  out.push(current);
  return out.map((value) => String(value || '').trim());
}

function toNumber(input) {
  if (input === null || input === undefined || input === '') return 0;
  const n = Number(String(input).replace(/[\s,$]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

let text = String($json.reportText || '').trim();
if (!text) {
  return [{ json: { bySku: {}, skuCount: 0, parseWarning: 'FBA report text empty' } }];
}
if (!text.includes('\n') && text.includes('\\n')) {
  text = text.replace(/\\r\\n/g, '\n').replace(/\\n/g, '\n').replace(/\\t/g, '\t');
}

const lines = text.split(/\r?\n/).filter((line) => line.trim());
if (lines.length < 2) {
  return [{ json: { bySku: {}, skuCount: 0, parseWarning: 'FBA report has no data rows' } }];
}

const delimiter = lines[0].includes('\t') ? '\t' : ',';
const headers = parseDelimitedLine(lines[0], delimiter);
const normalized = headers.map((header) => header.toLowerCase().replace(/[^a-z0-9]/g, ''));
const pickIndex = (candidates) => normalized.findIndex((header) => candidates.includes(header));

const skuIdx = pickIndex(['sku', 'sellersku', 'merchantsku']);
const fbaTotalIdx = pickIndex(['afntotalquantity']);
const fbaFulfillableIdx = pickIndex(['afnfulfillablequantity']);
const fbaUnsellableIdx = pickIndex(['afnunsellablequantity']);
const fbaReservedIdx = pickIndex(['afnreservedquantity']);

if (skuIdx === -1) {
  throw new Error('Could not locate SKU column in FBA stock report');
}

const bySku = {};
for (let i = 1; i < lines.length; i++) {
  const cols = parseDelimitedLine(lines[i], delimiter);
  const sku = String(cols[skuIdx] || '').trim();
  if (!sku) continue;

  const record = bySku[sku] || {
    sku,
    fbaTotalQuantity: 0,
    fbaFulfillableQuantity: 0,
    fbaUnsellableQuantity: 0,
    fbaReservedQuantity: 0,
    fbmQuantity: 0,
  };

  record.fbaFulfillableQuantity = Number((record.fbaFulfillableQuantity + (fbaFulfillableIdx === -1 ? 0 : toNumber(cols[fbaFulfillableIdx]))).toFixed(2));
  record.fbaUnsellableQuantity = Number((record.fbaUnsellableQuantity + (fbaUnsellableIdx === -1 ? 0 : toNumber(cols[fbaUnsellableIdx]))).toFixed(2));
  record.fbaReservedQuantity = Number((record.fbaReservedQuantity + (fbaReservedIdx === -1 ? 0 : toNumber(cols[fbaReservedIdx]))).toFixed(2));
  if (fbaTotalIdx !== -1) {
    record.fbaTotalQuantity = Number((record.fbaTotalQuantity + toNumber(cols[fbaTotalIdx])).toFixed(2));
  } else {
    record.fbaTotalQuantity = Number((record.fbaFulfillableQuantity + record.fbaUnsellableQuantity + record.fbaReservedQuantity).toFixed(2));
  }

  bySku[sku] = record;
}

return [{ json: { bySku, skuCount: Object.keys(bySku).length, parseWarning: null } }];

